func (s *Store) Status() (map[string]int, error) {
	rows, err := s.db.Query(
		`SELECT resource_type, COUNT(*) FROM resources GROUP BY resource_type ORDER BY resource_type`,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	status := make(map[string]int)
	for rows.Next() {
		var rt string
		var count int
		if err := rows.Scan(&rt, &count); err != nil {
			return nil, err
		}
		status[rt] = count
	}
	return status, rows.Err()
}

// ResolveByName resolves a human-readable name to a UUID from synced data.
// If the input is already a UUID, it is returned as-is.
// matchFields are JSON field names to search against (e.g., "name", "key", "email").
func (s *Store) ResolveByName(resourceType string, input string, matchFields ...string) (string, error) {
	if IsUUID(input) {
		return input, nil
	}

	var matches []string
	for _, field := range matchFields {
		query := fmt.Sprintf(
			`SELECT id FROM resources WHERE resource_type = ? AND LOWER(json_extract(data, '$.%s')) = LOWER(?)`,
			field,
		)
		rows, err := s.db.Query(query, resourceType, input)
		if err != nil {
			continue
		}
		for rows.Next() {
			var id string
			if rows.Scan(&id) == nil {
				// Deduplicate
				found := false
				for _, m := range matches {
					if m == id {
						found = true
						break
					}
				}
				if !found {
					matches = append(matches, id)
				}
			}
		}
		rows.Close()
	}

	switch len(matches) {
	case 0:
		return "", fmt.Errorf("%s %q not found in local store. Run 'sync' first, or use the UUID directly", resourceType, input)
	case 1:
		return matches[0], nil
	default:
		hint := matches[0]
		if len(matches) > 5 {
			hint = strings.Join(matches[:5], ", ") + "..."
		} else {
			hint = strings.Join(matches, ", ")
		}
		return "", fmt.Errorf("ambiguous: %q matches %d %s entries (%s). Use the exact UUID instead", input, len(matches), resourceType, hint)
	}
}

// LogDeeplineCall records a single Deepline tool execution for budget
// tracking. payloadHash is an opaque digest of the request payload (we do
// not store the payload itself because it may contain PII). cost is the
// estimated credit cost; status is a free-form string such as "ok",
// "dry-run", "error", etc.
func (s *Store) LogDeeplineCall(toolID, payloadHash string, cost int, status string) error {
	_, err := s.db.Exec(
		`INSERT INTO deepline_log (tool_id, payload_hash, cost_credits, status, timestamp)
		 VALUES (?, ?, ?, ?, CURRENT_TIMESTAMP)`,
		toolID, payloadHash, cost, status,
	)
	return err
}

// Person represents a unified person record across LinkedIn, Happenstance,
// and Deepline sources. One row per unique person, keyed by either
// linkedin_url or happenstance_uuid (whichever is available first).
type Person struct {
	ID               int64           `json:"id"`
	LinkedInURL      string          `json:"linkedin_url,omitempty"`
	HappenstanceUUID string          `json:"happenstance_uuid,omitempty"`
	FullName         string          `json:"full_name"`
	Title            string          `json:"title,omitempty"`
	Company          string          `json:"company,omitempty"`
	Location         string          `json:"location,omitempty"`
	ImageURL         string          `json:"image_url,omitempty"`
	Sources          []string        `json:"sources"`
	LIData           json.RawMessage `json:"li_data,omitempty"`
	HPData           json.RawMessage `json:"hp_data,omitempty"`
	DLData           json.RawMessage `json:"dl_data,omitempty"`
	FirstSeen        time.Time       `json:"first_seen,omitempty"`
	LastSeen         time.Time       `json:"last_seen,omitempty"`
}

// mergeSources merges two CSV source tag strings, deduping entries.
func mergeSources(existing, incoming string) string {
	set := map[string]bool{}
	var out []string
	for _, s := range strings.Split(existing, ",") {
		s = strings.TrimSpace(s)
		if s == "" || set[s] {
			continue
		}
		set[s] = true
		out = append(out, s)
	}
	for _, s := range strings.Split(incoming, ",") {
		s = strings.TrimSpace(s)
		if s == "" || set[s] {
			continue
		}
		set[s] = true
		out = append(out, s)
	}
	return strings.Join(out, ",")
}

// UpsertPerson inserts or updates a person by LinkedIn URL or Happenstance
// UUID. Incoming sources are merged with any existing CSV, and last_seen is
// refreshed. Returns the row id.
//
// Recognized keys in data:
//
//	linkedin_url, happenstance_uuid, full_name, title, company, location,
//	image_url, sources (string or []string), li_data, hp_data, dl_data.
func (s *Store) UpsertPerson(data map[string]any) (int64, error) {
	linkedinURL := getString(data, "linkedin_url")
	hpUUID := getString(data, "happenstance_uuid")
	fullName := getString(data, "full_name")
	if fullName == "" {
		return 0, fmt.Errorf("UpsertPerson: full_name is required")
	}
	if linkedinURL == "" && hpUUID == "" {
		return 0, fmt.Errorf("UpsertPerson: at least one of linkedin_url or happenstance_uuid is required")
	}

	title := getString(data, "title")
	company := getString(data, "company")
	location := getString(data, "location")
	imageURL := getString(data, "image_url")
	sources := coerceCSV(data["sources"])

	liJSON := rawJSON(data, "li_data")
	hpJSON := rawJSON(data, "hp_data")
	dlJSON := rawJSON(data, "dl_data")

	tx, err := s.db.Begin()
	if err != nil {
		return 0, err
	}
	defer tx.Rollback()

	// Look up existing by linkedin_url or happenstance_uuid.
	var (
		existingID       int64
		existingSources  string
		existingLI       sql.NullString
		existingHP       sql.NullString
		existingDL       sql.NullString
		existingLinkedIn sql.NullString
		existingHPUUID   sql.NullString
	)
	lookupQuery := `SELECT id, sources, li_data, hp_data, dl_data, linkedin_url, happenstance_uuid FROM people WHERE `
	args := []any{}
	conds := []string{}
	if linkedinURL != "" {
		conds = append(conds, "linkedin_url = ?")
		args = append(args, linkedinURL)
	}
	if hpUUID != "" {
		conds = append(conds, "happenstance_uuid = ?")
		args = append(args, hpUUID)
	}
	lookupQuery += strings.Join(conds, " OR ") + " LIMIT 1"

	row := tx.QueryRow(lookupQuery, args...)
	err = row.Scan(&existingID, &existingSources, &existingLI, &existingHP, &existingDL, &existingLinkedIn, &existingHPUUID)

	now := time.Now()
	if err == sql.ErrNoRows {
		// Insert.
		res, insErr := tx.Exec(
			`INSERT INTO people (linkedin_url, happenstance_uuid, full_name, title, company, location, image_url, sources, li_data, hp_data, dl_data, first_seen, last_seen)
			 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
			nullIfEmpty(linkedinURL), nullIfEmpty(hpUUID), fullName, title, company, location, imageURL,
			sources, nullIfEmptyJSON(liJSON), nullIfEmptyJSON(hpJSON), nullIfEmptyJSON(dlJSON), now, now,
		)
		if insErr != nil {
			return 0, fmt.Errorf("inserting person: %w", insErr)
		}
		id, _ := res.LastInsertId()
		_, _ = tx.Exec(
			`INSERT INTO people_fts (rowid, full_name, title, company, location) VALUES (?, ?, ?, ?, ?)`,
			id, fullName, title, company, location,
		)
		if err := tx.Commit(); err != nil {
			return 0, err
		}
		return id, nil
	}
	if err != nil {
		return 0, fmt.Errorf("looking up person: %w", err)
	}

	// Update.
	mergedSources := mergeSources(existingSources, sources)
	newLinkedIn := existingLinkedIn.String
	if linkedinURL != "" {
		newLinkedIn = linkedinURL
	}
	newHPUUID := existingHPUUID.String
	if hpUUID != "" {
		newHPUUID = hpUUID
	}
	newLI := existingLI.String
	if len(liJSON) > 0 {
		newLI = string(liJSON)
	}
	newHP := existingHP.String
	if len(hpJSON) > 0 {
		newHP = string(hpJSON)
	}
	newDL := existingDL.String
	if len(dlJSON) > 0 {
		newDL = string(dlJSON)
	}

	_, err = tx.Exec(
		`UPDATE people SET
			linkedin_url = ?,
			happenstance_uuid = ?,
			full_name = ?,
			title = COALESCE(NULLIF(?, ''), title),
			company = COALESCE(NULLIF(?, ''), company),
			location = COALESCE(NULLIF(?, ''), location),
			image_url = COALESCE(NULLIF(?, ''), image_url),
			sources = ?,
			li_data = ?,
			hp_data = ?,
			dl_data = ?,
			last_seen = ?
		 WHERE id = ?`,
		nullIfEmpty(newLinkedIn), nullIfEmpty(newHPUUID), fullName, title, company, location, imageURL,
		mergedSources, nullIfEmpty(newLI), nullIfEmpty(newHP), nullIfEmpty(newDL), now, existingID,
	)
	if err != nil {
		return 0, fmt.Errorf("updating person: %w", err)
	}
	_, _ = tx.Exec(`DELETE FROM people_fts WHERE rowid = ?`, existingID)
	_, _ = tx.Exec(
		`INSERT INTO people_fts (rowid, full_name, title, company, location) VALUES (?, ?, ?, ?, ?)`,
		existingID, fullName, title, company, location,
	)

	if err := tx.Commit(); err != nil {
		return 0, err
	}
	return existingID, nil
}

// GetPersonByLinkedInURL returns a person by LinkedIn URL, or nil if not found.
func (s *Store) GetPersonByLinkedInURL(linkURL string) (*Person, error) {
	return s.queryOnePerson(
		`SELECT id, linkedin_url, happenstance_uuid, full_name, title, company, location, image_url, sources, li_data, hp_data, dl_data, first_seen, last_seen
		 FROM people WHERE linkedin_url = ? LIMIT 1`,
		linkURL,
	)
}

// GetPersonByUUID returns a person by Happenstance UUID, or nil if not found.
func (s *Store) GetPersonByUUID(uuid string) (*Person, error) {
	return s.queryOnePerson(
		`SELECT id, linkedin_url, happenstance_uuid, full_name, title, company, location, image_url, sources, li_data, hp_data, dl_data, first_seen, last_seen
		 FROM people WHERE happenstance_uuid = ? LIMIT 1`,
		uuid,
	)
}

// GetPeopleByCompany returns all people whose company field matches the
// given string (case-insensitive substring match).
func (s *Store) GetPeopleByCompany(company string) ([]*Person, error) {
	rows, err := s.db.Query(
		`SELECT id, linkedin_url, happenstance_uuid, full_name, title, company, location, image_url, sources, li_data, hp_data, dl_data, first_seen, last_seen
		 FROM people WHERE LOWER(company) LIKE LOWER(?) ORDER BY full_name`,
		"%"+company+"%",
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanPeople(rows)
}

// GetMutualConnections returns people who have connection_edges from both a
// LinkedIn source and a Happenstance source (mutuals across both networks).
// The input is either a LinkedIn URL or Happenstance UUID for the target
// person; the mutual list is the viewer's own network intersected with
// sources.
//
// For v1 this returns people with edges in BOTH {linkedin_1deg} AND
// {happenstance_friend, happenstance_network}. The target lookup argument is
// currently informational; true mutual-by-target requires the target's own
// network which LinkedIn MCP does not expose.
func (s *Store) GetMutualConnections(linkedinURLOrUUID string) ([]*Person, error) {
	_ = linkedinURLOrUUID // reserved for future scoping once target connections are available
	rows, err := s.db.Query(
		`SELECT DISTINCT p.id, p.linkedin_url, p.happenstance_uuid, p.full_name, p.title, p.company, p.location, p.image_url, p.sources, p.li_data, p.hp_data, p.dl_data, p.first_seen, p.last_seen
		 FROM people p
		 WHERE EXISTS (SELECT 1 FROM connection_edges e1 WHERE e1.person_id = p.id AND e1.source LIKE 'linkedin_%')
		   AND EXISTS (SELECT 1 FROM connection_edges e2 WHERE e2.person_id = p.id AND e2.source LIKE 'happenstance_%')
		 ORDER BY p.full_name`,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanPeople(rows)
}

// GetConnectionCount returns the number of edges a person has for a given
// source (e.g. "happenstance_friend"). Returns 0 if none.
func (s *Store) GetConnectionCount(personID int64, source string) (int, error) {
	var count int
	err := s.db.QueryRow(
		`SELECT COUNT(*) FROM connection_edges WHERE person_id = ? AND source = ?`,
		personID, source,
	).Scan(&count)
	if err == sql.ErrNoRows {
		return 0, nil
	}
	return count, err
}

// AddConnectionEdge inserts a connection_edges row. Silently succeeds if an
// equivalent edge already exists (via UNIQUE-ish best-effort: we check first).
func (s *Store) AddConnectionEdge(viewerIdentity string, personID int64, source string, strength int) error {
	if strength <= 0 {
		strength = 1
	}
	// Dedupe: skip if (viewer_identity, person_id, source) already present.
	var existing int
	err := s.db.QueryRow(
		`SELECT COUNT(*) FROM connection_edges WHERE viewer_identity = ? AND person_id = ? AND source = ?`,
		viewerIdentity, personID, source,
	).Scan(&existing)
	if err != nil {
		return err
	}
	if existing > 0 {
		return nil
	}
	_, err = s.db.Exec(
		`INSERT INTO connection_edges (viewer_identity, person_id, source, strength) VALUES (?, ?, ?, ?)`,
		viewerIdentity, personID, source, strength,
	)
	return err
}

// GetDeeplineLogHistory returns recent Deepline calls ordered newest-first.
// Each entry has tool_id, cost_credits, status, timestamp.
func (s *Store) GetDeeplineLogHistory(limit int) ([]map[string]any, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT id, tool_id, cost_credits, status, timestamp FROM deepline_log ORDER BY timestamp DESC LIMIT ?`,
		limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var (
			id   int64
			tool string
			cost sql.NullInt64
			stat sql.NullString
			ts   sql.NullString
		)
		if err := rows.Scan(&id, &tool, &cost, &stat, &ts); err != nil {
			return nil, err
		}
		out = append(out, map[string]any{
			"id":           id,
			"tool_id":      tool,
			"cost_credits": cost.Int64,
			"status":       stat.String,
			"timestamp":    ts.String,
		})
	}
	return out, rows.Err()
}

// DeeplineTopToolsBySpend returns the top tools by credit spend within the
// last sinceHours hours (0 = all time). Only rows with status='ok' count.
func (s *Store) DeeplineTopToolsBySpend(sinceHours, limit int) ([]map[string]any, error) {
	if limit <= 0 {
		limit = 10
	}
	var rows *sql.Rows
	var err error
	if sinceHours <= 0 {
		rows, err = s.db.Query(
			`SELECT tool_id, COUNT(*) AS n, COALESCE(SUM(cost_credits),0) AS total
			 FROM deepline_log WHERE status='ok'
			 GROUP BY tool_id ORDER BY total DESC LIMIT ?`, limit,
		)
	} else {
		rows, err = s.db.Query(
			`SELECT tool_id, COUNT(*) AS n, COALESCE(SUM(cost_credits),0) AS total
			 FROM deepline_log WHERE status='ok' AND timestamp >= datetime('now', ?)
			 GROUP BY tool_id ORDER BY total DESC LIMIT ?`,
			fmt.Sprintf("-%d hours", sinceHours), limit,
		)
	}
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var tool string
		var n, total int
		if err := rows.Scan(&tool, &n, &total); err != nil {
			return nil, err
		}
		out = append(out, map[string]any{
			"tool_id": tool,
			"calls":   n,
			"credits": total,
		})
	}
	return out, rows.Err()
}

// --- internal helpers ---

func (s *Store) queryOnePerson(query string, args ...any) (*Person, error) {
	row := s.db.QueryRow(query, args...)
	p, err := scanPerson(row)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	return p, err
}

type rowScanner interface {
	Scan(dest ...any) error
}

func scanPerson(row rowScanner) (*Person, error) {
	var (
		p                   Person
		li, uuid            sql.NullString
		title, company, loc sql.NullString
		img, sources        sql.NullString
		liData, hpData, dl  sql.NullString
		first, last         sql.NullTime
	)
	err := row.Scan(&p.ID, &li, &uuid, &p.FullName, &title, &company, &loc, &img, &sources,
		&liData, &hpData, &dl, &first, &last)
	if err != nil {
		return nil, err
	}
	p.LinkedInURL = li.String
	p.HappenstanceUUID = uuid.String
	p.Title = title.String
	p.Company = company.String
	p.Location = loc.String
	p.ImageURL = img.String
	if sources.String != "" {
		for _, s := range strings.Split(sources.String, ",") {
			s = strings.TrimSpace(s)
			if s != "" {
				p.Sources = append(p.Sources, s)
			}
		}
	}
	if liData.String != "" {
		p.LIData = json.RawMessage(liData.String)
	}
	if hpData.String != "" {
		p.HPData = json.RawMessage(hpData.String)
	}
	if dl.String != "" {
		p.DLData = json.RawMessage(dl.String)
	}
	if first.Valid {
		p.FirstSeen = first.Time
	}
	if last.Valid {
		p.LastSeen = last.Time
	}
	return &p, nil
}

func scanPeople(rows *sql.Rows) ([]*Person, error) {
	var out []*Person
	for rows.Next() {
		p, err := scanPerson(rows)
		if err != nil {
			return nil, err
		}
		out = append(out, p)
	}
	return out, rows.Err()
}

func getString(m map[string]any, key string) string {
	if v, ok := m[key]; ok && v != nil {
		return fmt.Sprintf("%v", v)
	}
	return ""
}

func coerceCSV(v any) string {
	if v == nil {
		return ""
	}
	switch x := v.(type) {
	case string:
		return x
	case []string:
		return strings.Join(x, ",")
	case []any:
		parts := make([]string, 0, len(x))
		for _, item := range x {
			parts = append(parts, fmt.Sprintf("%v", item))
		}
		return strings.Join(parts, ",")
	}
	return fmt.Sprintf("%v", v)
}

func rawJSON(m map[string]any, key string) json.RawMessage {
	v, ok := m[key]
	if !ok || v == nil {
		return nil
	}
	if raw, ok := v.(json.RawMessage); ok {
		return raw
	}
	if s, ok := v.(string); ok {
		if s == "" {
			return nil
		}
		if json.Valid([]byte(s)) {
			return json.RawMessage(s)
		}
	}
	b, err := json.Marshal(v)
	if err != nil {
		return nil
	}
	return b
}

func nullIfEmpty(s string) any {
	if s == "" {
		return nil
	}
	return s
}

func nullIfEmptyJSON(r json.RawMessage) any {
	if len(r) == 0 {
		return nil
	}
	return string(r)
}

// SumDeeplineCost returns the total estimated credit spend over the last
// sinceHours hours. Rows with status != "ok" are excluded so dry-runs and
// failed calls do not inflate the total. If sinceHours <= 0 the full history
// is summed.
func (s *Store) SumDeeplineCost(sinceHours int) int {
	var total sql.NullInt64
	var err error
	if sinceHours <= 0 {
		err = s.db.QueryRow(
			`SELECT COALESCE(SUM(cost_credits), 0) FROM deepline_log WHERE status = 'ok'`,
		).Scan(&total)
	} else {
		err = s.db.QueryRow(
			`SELECT COALESCE(SUM(cost_credits), 0) FROM deepline_log
			 WHERE status = 'ok' AND timestamp >= datetime('now', ?)`,
			fmt.Sprintf("-%d hours", sinceHours),
		).Scan(&total)
	}
	if err != nil {
		return 0
	}
	return int(total.Int64)
}
